def second_largest(numbers):
    """
    Returns the second-largest unique number in the list.
    If there are fewer than two distinct numbers, returns None.
    """
    if len(numbers) < 2:
        return None
    # Get unique numbers
    unique = list(set(numbers))
    if len(unique) < 2:
        return None
    # Find the maximum
    max_val = max(unique)
    # Remove the maximum and find the next maximum
    unique.remove(max_val)
    return max(unique)

# Alternative one-pass solution without using set (more memory efficient for large lists)
def second_largest_one_pass(numbers):
    if len(numbers) < 2:
        return None
    first = second = float('-inf')
    for num in numbers:
        if num > first:
            second = first
            first = num
        elif num > second and num != first:
            second = num
    return second if second != float('-inf') else None
